let input = {};
try { input = $input.item.json; } catch(e) {}
try { if (!input || !input.businessName) input = $json; } catch(e) {}

const projectType = input.projectType || 'landing_page';
const businessName = input.businessName || 'My Business';
const languages = input.languages || ['hu'];
const description = input.description || '';
const designStyle = input.designStyle || 'modern';
const aiModel = input.aiModel || 'deepseek-v4-flash';
const customPrompt = input.customPrompt || '';
const apiKeyOverride = input.apiKeyOverride || '';
const notifyEmail = input.notifyEmail || '';
const logoMode = input.logoMode || 'upload';
const logoPrompt = input.logoPrompt || '';
const colors = input.colors || { primary: '#6366f1', secondary: '#8b5cf6', accent: '#f59e0b', headerBg: '#ffffff' };
const headerLogo = input.headerLogo || null;
const footerLogo = input.footerLogo || null;
const header = input.header || [];
const footer = input.footer || [];
const hero = input.hero || { enabled: true, height: 600 };

let pages = input.pages || [];
if (pages.length > 0 && typeof pages[0] === 'string') {
  pages = pages.map(p => ({ name: p, slug: p.toLowerCase(), description: '', subpages: [] }));
}

if (pages.length === 0) {
  pages = [
    { name: 'Kezdőlap', slug: 'home', description: 'Főoldal', subpages: [] },
    { name: 'Rólunk', slug: 'about', description: 'Cégbemutató', subpages: [] },
    { name: 'Kapcsolat', slug: 'contact', description: 'Elérhetőségek', subpages: [] }
  ];
  if (projectType === 'corporate' || projectType === 'blog' || projectType === 'portfolio') {
    pages.push({ name: 'Szolgáltatások', slug: 'services', description: 'Szolgáltatások', subpages: [] });
  }
  if (projectType === 'shop') {
    pages.push({ name: 'Termékek', slug: 'products', description: 'Termékkatalógus', subpages: [] });
  }
}

return { businessName, projectType, languages, description, designStyle, aiModel, customPrompt, apiKeyOverride, notifyEmail, logoMode, logoPrompt, colors, headerLogo, footerLogo, header, hero, footer, pages };

const https = require('https');

const data = $input.all()[0].json;
const lang = data.languages[0] || 'hu';

const pageList = data.pages.map(p => {
  let line = p.name + ' (' + p.slug + ')';
  if (p.description) line += ': ' + p.description;
  return line;
}).join('\n');

const heroInfo = data.hero && data.hero.enabled ? `Hero: yes, height=${data.hero.height}px` : 'Hero: no';

const base = `Create a complete website for:
Business: ${data.businessName} | Type: ${data.projectType}
Language: ${lang} | Design: ${data.designStyle}
Description: ${data.description}
Colors: ${data.colors.primary}, ${data.colors.secondary}, ${data.colors.accent}
${heroInfo}

Pages: ${pageList}

Return a JSON with:
- "pages": each page has title, meta, content (hero for home, sections with title and text)
- "images": array of image prompts for AI image generation. Include: page_slug, section, prompt (concise English description).
- "config": system (site_name, language), theme (colors), header, footer, plugins
- "animations": CSS animation suggestions
- "admin_structure": blueprints

Create SEO-optimized content in ${lang}. Return CLEAN JSON only.`;

const prompt = data.customPrompt ? base + '\n\nCUSTOM: ' + data.customPrompt : base;
const apiKey = data.apiKeyOverride || $env.DEEPSEEK_API_KEY || '';
if (!apiKey) throw new Error('Missing API key');

const requestBody = JSON.stringify({
  model: data.aiModel, messages: [{ role: 'system', content: 'You are a web designer. Return pure JSON.' }, { role: 'user', content: prompt }],
  temperature: 0.7, max_tokens: 4096, response_format: { type: 'json_object' }
});

const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.deepseek.com', port: 443, path: '/v1/chat/completions', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey, 'Content-Length': Buffer.byteLength(requestBody) }, timeout: 120000
  }, (res) => {
    let body = ''; res.on('data', chunk => body += chunk);
    res.on('end', () => { try { const j = JSON.parse(body); if (j.error) reject(new Error(j.error.message)); else resolve(j); } catch(e) { reject(new Error(body.substring(0,200))); } });
  });
  req.on('error', reject); req.on('timeout', () => { req.destroy(); reject(new Error('Timeout')); });
  req.write(requestBody); req.end();
});

return { ...result, _businessName: data.businessName };

const fs = require('fs');
const path = require('path');
const https = require('https');
const zlib = require('zlib');

const response = $input.all()[0].json;

// ---- Parse ----
let content; let rawText = '';
if (response.choices) {
  rawText = response.choices[0].message.content;
  try { content = JSON.parse(rawText); } catch(e) {
    try { const m = rawText.match(/\{[\s\S]*\}/); if (m) content = JSON.parse(m[0]); else throw e; } catch(e2) {
      content = { error: "Parse failed", raw: rawText.substring(0,2000) };
    }
  }
} else { content = { error: "No response" }; }

const bizName = response._businessName || 'unknown';
const safeName = bizName.toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 30);
const ts = Date.now();
const archiveName = safeName + '_' + ts + '_website.tar.gz';

// ---- Könyvtárak ----
const outputDir = '/home/node/output';
const workDir = path.join(outputDir, 'build_' + safeName + '_' + ts);
const pagesDir = path.join(workDir, 'pages');
const imagesDir = path.join(workDir, 'images');
[workDir, pagesDir, imagesDir].forEach(d => { try { if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true }); } catch(err) {} });

// ---- KÉPEK ----
let imageMap = {};
if (content.images && Array.isArray(content.images)) {
  for (const img of content.images.slice(0, 4)) {
    if (!img.prompt) continue;
    const encodedPrompt = encodeURIComponent(img.prompt);
    const imageUrl = `https://image.pollinations.ai/prompt/${encodedPrompt}?width=800&height=600&nologo=true`;
    const imgFilename = (img.page_slug || 'img') + '_' + Date.now() + '.jpg';
    const imgPath = path.join(imagesDir, imgFilename);
    try {
      await new Promise((resolve) => {
        const file = fs.createWriteStream(imgPath);
        https.get(imageUrl, (res) => {
          if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
            https.get(res.headers.location, (redir) => { redir.pipe(file); file.on('finish', () => { file.close(); resolve(); }); }).on('error', () => resolve());
          } else { res.pipe(file); file.on('finish', () => { file.close(); resolve(); }); }
        }).on('error', () => resolve());
      });
      imageMap[img.page_slug || 'general'] = 'images/' + imgFilename;
    } catch(err) {}
  }
}

// Fallback SVG
if (Object.keys(imageMap).length === 0 && content.pages) {
  Object.keys(content.pages).forEach((slug, idx) => {
    const color = [content.config?.theme?.colors?.primary, '#6366f1', '#8b5cf6', '#f59e0b'][idx % 4];
    const svg = `<svg width="800" height="400" xmlns="http://www.w3.org/2000/svg"><rect width="100%" height="100%" fill="${color}"/><text x="50%" y="50%" dominant-baseline="middle" text-anchor="middle" font-family="Arial" font-size="24" fill="white">${content.pages[slug]?.title || slug}</text></svg>`;
    const fn = 'page_' + slug + '.svg';
    try { fs.writeFileSync(path.join(imagesDir, fn), svg); imageMap[slug] = 'images/' + fn; } catch(err) {}
  });
}

// ---- .md FÁJLOK ----
if (content.pages) {
  Object.keys(content.pages).forEach(slug => {
    const page = content.pages[slug];
    const mdName = slug === 'home' ? '01.home' : slug + '.md';
    let md = '---\ntitle: "' + (page.title || slug) + '"\nvisible: true\n---\n\n';
    if (slug === 'home' && page.content && page.content.hero) {
      const heroImg = imageMap['home_hero'] || imageMap['home'] || '';
      if (heroImg) md += `![Hero](${heroImg})\n\n`;
      md += '# ' + (page.content.hero.title || '') + '\n\n' + (page.content.hero.subtitle || '') + '\n\n';
    }
    if (page.content && page.content.sections) {
      page.content.sections.forEach(sec => {
        md += '## ' + (sec.title || '') + '\n\n' + (sec.content || '') + '\n\n';
        const key = slug + '_' + (sec.title || '').toLowerCase().replace(/\s+/g,'_');
        if (imageMap[key]) md += `![${sec.title || ''}](${imageMap[key]})\n\n`;
      });
    }
    try { fs.writeFileSync(path.join(pagesDir, mdName), md, 'utf8'); } catch(err) {}
  });
} else {
  try { fs.writeFileSync(path.join(pagesDir, '01.home'), '---\ntitle: "' + bizName + '"\n---\n\n# ' + bizName + '\n\n' + rawText, 'utf8'); } catch(err) {}
}

// ---- README ----
let readme = '# ' + bizName + '\n\nGenerated by n8n-gravity v1.5.1\n\n';
if (content.config) {
  if (content.config.system) readme += '**Site:** ' + (content.config.system.site_name || '') + '\n';
  if (content.config.theme && content.config.theme.colors) {
    readme += '**Colors:** ' + Object.entries(content.config.theme.colors).map(([k,v])=>k+'='+v).join(', ') + '\n';
  }
  if (content.config.plugins) readme += '**Plugins:** ' + content.config.plugins.join(', ') + '\n';
}
if (content.animations) readme += '**Animations:** ' + content.animations.join(', ') + '\n';
try { fs.writeFileSync(path.join(workDir, 'README.md'), readme, 'utf8'); } catch(err) {}

// ---- TAR.GZ csomagolás (Node.js zlib) ----
const archivePath = path.join(outputDir, archiveName);
try {
  const files = [];
  function walk(dir, basePath) {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) { walk(fullPath, basePath); }
      else { files.push({ path: fullPath, relative: path.relative(basePath, fullPath) }); }
    }
  }
  walk(workDir, outputDir);

  // Egyszerű TAR formátum + gzip
  const zipped = zlib.gzipSync(Buffer.concat(files.map(f => {
    const relative = f.relative.replace(workDir + '/', '');
    const header = Buffer.alloc(512);
    header.write(relative.substring(0, 99), 0, 'utf8');
    const size = fs.statSync(f.path).size.toString(8);
    header.write(size, 124, 11, 'utf8');
    header[156] = 0x30; // regular file
    const content = fs.readFileSync(f.path);
    const blocks = Math.ceil(content.length / 512);
    const padded = Buffer.alloc(blocks * 512);
    content.copy(padded);
    return Buffer.concat([header, padded]);
  })));
  fs.writeFileSync(archivePath, Buffer.concat([zipped, Buffer.alloc(1024)]));
  fs.chmodSync(archivePath, 0o666);
} catch(err) {
  // Fallback: json mentés
}

// ---- JSON export ----
const jsonFile = path.join(outputDir, safeName + '_' + ts + '.json');
try { fs.writeFileSync(jsonFile, JSON.stringify(content, null, 2), 'utf8'); } catch(err) {}

// ---- Jogosultságok ----
try { require('child_process').execSync('chmod -R 777 ' + outputDir, { timeout: 2000 }); } catch(err) {}

return {
  generated: content,
  saved_to: archiveName,
  pages_count: content.pages ? Object.keys(content.pages).length : 0,
  images_count: Object.keys(imageMap).length,
  timestamp: new Date().toISOString(),
  model: response.model || 'deepseek-v4-flash'
};
